const COMPANY_IMAGES = {
  micro: 'data:image/png;base64,',
  small: 'data:image/png;base64,',
  medium: 'data:image/png;base64,',
  large: 'data:image/png;base64,',
  international: 'data:image/png;base64,',
  multinational: 'data:image/png;base64,',
};

function getCompanyLevel(gd) {
  const emps = (gd.employees || []).length;
  const rev = gd.finances?.monthly_revenue || 0;
  const exports = (gd.trade?.exports || []).length;
  const franchise = gd.franchise;
  
  if (franchise?.mode === 'franquiciador' && exports >= 3) return { level: 'multinational', name: 'Multinacional', desc: 'Presència global amb franquícies i exportacions' };
  if (exports >= 2 || (emps >= 50 && rev >= 200000)) return { level: 'international', name: 'Internacional', desc: 'Operacions a l\'estranger' };
  if (emps >= 25 || rev >= 100000) return { level: 'large', name: 'Gran empresa', desc: 'Líder del sector al Vallès' };
  if (emps >= 10 || rev >= 40000) return { level: 'medium', name: 'Empresa mitjana', desc: 'Consolidada i en creixement' };
  if (emps >= 3 || rev >= 10000) return { level: 'small', name: 'Petita empresa', desc: 'Equip en formació' };
  return { level: 'micro', name: 'Microempresa', desc: 'Tot just començant' };
}

